  standalone: false,
})
export class HomePage {
  private popoverCtrl = inject(PopoverController);
  private alertCtrl = inject(AlertController);
  botService = inject(BotService);

  public async addBot(ev) {
    const popover = await this.popoverCtrl.create({
      component: FactionMenuComponent,
      event: ev,
      translucent: true,
      cssClass: "wider",
    });

    popover.onDidDismiss().then((res) => {
      if (!res || !res.data) {
        return;
      }

      this.botService.addBot(new this.botService.botHash[res.data]());
    });

    return await popover.present();
  }

  public async reset() {
    const alert = await this.alertCtrl.create({
      header: "Reset Your Bots?",
      message:
        "This will reset all rules, victory points, traits, and any other settings you have set.",
      buttons: [
        {
          text: "Cancel",
          role: "cancel",
          cssClass: "secondary",
        },
        {
          text: "Yes, reset!",
          handler: () => {
            this.botService.clearBots();
          },
        },
      ],
    });

    await alert.present();
  }
}

