import { Component, Input, inject } from "@angular/core";
import { Bot } from "../models/bot";
import { BotService } from "../bot.service";
import { RendererService } from "../renderer.service";
import { TranslateService } from "@ngx-translate/core";
import { ToastController } from "@ionic/angular";

export interface MetaData {
  text: string;
  type: string;
  value: unknown;
}

@Component({
  selector: "para",
  templateUrl: "./paragraph.component.html",
  styleUrls: ["./paragraph.component.scss"],
})
export class ParagraphComponent {
  rendererService = inject(RendererService);
  translateService = inject(TranslateService);
  botService = inject(BotService);
  toastController = inject(ToastController);

  @Input() public metadata: MetaData;
  @Input() public bot: Bot;

  public async updateScore(score: number): Promise<void> {
    this.bot.addVP(score);
    const botname = this.botService.botMeta[this.bot.name].fullName;
    const translatedBotName = this.translateService.instant(
      "Factions." + botname,
    );

    const toast = await this.toastController.create({
      message: this.translateService.instant("ToastMessages.UpdateScore", {
        botname: translatedBotName,
        addend: score,
      }),
      duration: 3000,
      position: "bottom",
      buttons: [
        {
          text: this.translateService.instant("ToastMessages.Actions.Undo"),
          handler: () => {
            this.bot.addVP(-score);
          },
        },
      ],
    });
    toast.present();
  }
}

import { Injectable } from "@angular/core";

import { marked, Renderer } from "marked";

@Injectable({
  providedIn: "root",
})
export class RendererService {
  private renderer: any;

  constructor() {
    this.renderer = this.getCustomRenderer();
  }

  private getCustomRenderer(): Renderer {
    const renderer = new Renderer();

    renderer.strong = (text: string) => {
      if (text.includes(":")) {
        const [type, subtype] = text.split(":");
        return `<img src="assets/inicon/${type}-${subtype}.png" class="inline-icon" />`;
      }
      return `<strong>${text}</strong>`;
    };

    renderer.paragraph = (text: string) => {
      return `<p class="paragraph">${text}</p>`;
    };

    return renderer;
  }

  public formatString(str: string): string {
    if (!str) {
      return "";
    }
    return marked(str, { renderer: this.renderer });
  }
}

